    private String extractTimestamp(SOAPHeader header) throws Exception {
        NodeList timestampNodes = header.getElementsByTagNameNS(TIMESTAMP_NS, "Timestamp");
        if (timestampNodes.getLength() > 0) {
            Node timestampNode = timestampNodes.item(0);
            NodeList childNodes = timestampNode.getChildNodes();
            for (int i = 0; i < childNodes.getLength(); i++) {
                Node child = childNodes.item(i);
                if ("Created".equals(child.getLocalName())) {
                    return child.getTextContent();
                }
            }
        }
        return null;
    }
    
    private boolean validateTimestamp(String timestamp) {
        try {
            SimpleDateFormat sdf = new SimpleDateFormat("yyyy-MM-dd'T'HH:mm:ss.SSS'Z'");
            sdf.setTimeZone(TimeZone.getTimeZone("UTC"));
            Date createdTime = sdf.parse(timestamp);
            
            // Check if timestamp is within acceptable range (e.g., 5 minutes)
            Calendar now = GregorianCalendar.getInstance();
            Calendar created = GregorianCalendar.getInstance();
            created.setTime(createdTime);
            
            long diffMinutes = (now.getTimeInMillis() - created.getTimeInMillis()) / (60 * 1000);
            
            return Math.abs(diffMinutes) <= 5;
        } catch (Exception e) {
            return false;
        }
    }
